const Header = () => {
    return (
        <header style={styles.header}>
            <div style={styles.container}>
                <div style={styles.logo}>MyLogo</div>
                <input type="text" placeholder="Search..." style={styles.search} />
                <nav style={styles.nav}>
                    <a href="#events" style={styles.navLink}>Events</a>
                    <a href="#clubs" style={styles.navLink}>Clubs</a>
                    <a href="#forms" style={styles.navLink}>Forms</a>
                    <a href="#talks" style={styles.navLink}>Talks</a>
                </nav>
                <button style={styles.loginBtn}>Log In</button>
            </div>
        </header>
    );
};

const styles = {
    header: {
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100%',
        backgroundColor: '#041E42',
        color: 'white',
        boxSizing: 'border-box',
        zIndex: 1000,
        padding: '10px 0',           // padding top/bottom only, horizontal handled by container
    },
    container: {
        maxWidth: '1200px',          // max width of the content area
        margin: '0 auto',            // center horizontally
        display: 'flex',
        alignItems: 'center',
        padding: '0 20px',           // horizontal padding inside container
    },
    logo: {
        fontWeight: 'bold',
        fontSize: '1.5rem',
        marginRight: '20px',
        flexShrink: 0,
    },
    search: {
        backgroundColor: '#6f7680',
        padding: '5px 10px',
        fontSize: '1rem',
        borderRadius: '1px',
        border: 'none',
        flexBasis: '300px',
        flexShrink: 1,
        marginRight: '20px',
    },
    nav: {
        display: 'flex',
        gap: '15px',
        marginRight: '20px',
        flexShrink: 0,
    },
    navLink: {
        color: 'white',
        textDecoration: 'none',
        fontWeight: '500',
        height: '100%',
        padding: '0 15px',
        borderRight: '1px solid gray',
        display: 'flex',
        alignItems: 'center',
    },
    loginBtn: {
        padding: '8px 15px',
        fontSize: '1rem',
        borderRadius: '4px',
        border: 'none',
        cursor: 'pointer',
        flexShrink: 0,
    },
};

export default Header;
